import { create } from 'zustand';
import { combine } from 'zustand/middleware';

import type { FilterFieldSuggestion } from '../suggestions/Suggestion.types.js';

type ApplySuggestionAction = {
  type: 'applySuggestion';
  data: {
    value: string;
  } & Partial<FilterFieldSuggestion>;
};

type DeleteStatementAction = {
  type: 'deleteStatement';
  data: {
    value: string;
    range: { from: number; to: number };
    newCursorPos: number;
  };
};

type ClearFilterAction = {
  type: 'clearFilter';
  data: {
    value: string;
  };
};

type HandleOnChangeAction = {
  type: 'handleOnChange';
  data: {
    value: string;
    newValue: string;
  };
};

type ControlledValueChangeAction = {
  type: 'controlledValueChange';
  data: {
    value: string;
    newValue: string;
  };
};

type FilterFieldUserActions =
  | ApplySuggestionAction
  | ClearFilterAction
  | ControlledValueChangeAction
  | DeleteStatementAction
  | HandleOnChangeAction;

type ErrorLogsState = {
  cursorPosition: number;
  action: FilterFieldUserActions | null;
  isControlled: boolean;
};

type ErrorLogsStateActions = {
  setCursorPosition: (pos: ErrorLogsState['cursorPosition']) => void;
  setAction: (action: ErrorLogsState['action']) => void;
  setIsControlled: (value: boolean) => void;
};

const initialState: ErrorLogsState = {
  cursorPosition: 0,
  action: null,
  isControlled: false,
};

/** @internal */
export const useErrorLogsStore = create<ErrorLogsState & ErrorLogsStateActions>(
  combine(initialState, (set) => ({
    setCursorPosition(pos: number) {
      set({
        cursorPosition: pos,
      });
    },
    setAction(action: FilterFieldUserActions | null) {
      set({
        action: action,
      });
    },
    setIsControlled(value: boolean) {
      set({
        isControlled: value,
      });
    },
  })),
);
